1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
14	
15	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
16	
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	
20	const formsAComponentBlock = (items: Item[]): boolean =>
21	  items.length === COMPONENT_BLOCK_SIZE;
22	
23	const sumOfBasePremiums = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
25	
26	const totalBasePremium = (items: Item[]): number =>
27	  formsAComponentBlock(items) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(items);
28	
29	const quotePremium = (step: QuoteStep): number =>
30	  totalBasePremium(step.items) + PROCESSING_FEE;
31	
32	const resultFor = (step: QuoteStep) => ({ premium: quotePremium(step) });
33	
34	export const runScenario = (input: unknown): unknown => {
35	  const scenario = input as Scenario;
36	  return { results: scenario.steps.map(resultFor) };
37	};
